static boolean validLength(int valueLength, CreditCardRange range) {
    if (range.lengths != null) {
        for (int length : range.lengths) {
            if (valueLength == length) {
                return true;
            }
        }
        return false;
    }
    return valueLength >= range.minLen && valueLength <= range.maxLen;
}

